        personData.starName = personData.star?["一白水星","二黒土星","三碧木星","四緑木星","五黄土星","六白金星","七赤金星","八白土星","九紫火星"][personData.star-1]:"";

        const ageGroup = !age ? "young" : age<25 ? "young" : age<40 ? "adult" : age<55 ? "middle" : "senior";

