        const marriageText = `${marriageBase} ${personData.starName}は『${kyusei.energy}』の星なので、出会いは「${kyusei.theme}」がテーマ。${personData.sign}的には対人関係が動きやすく、特に${marriageStartYear+1}年は重要な縁の節目になりやすいよ。`;

        const careerTitle = ageGroup==="young"
